// Mode: Run Once for All Items
// Extrai as URLs das imagens, 1 imagem por row, com id e foto_index.
const rows = [];
const items = $input.all();

for (const item of items) {
  const e = item.json || {};
  const idEstabelecimento = e.id || null;

  let fotos = [];
  try {
    fotos = typeof e.fotos === "string" ? JSON.parse(e.fotos) : (e.fotos || []);
  } catch (err) {
    fotos = [];
  }
  if (!Array.isArray(fotos)) fotos = [];

  const urlsProcessadas = new Set();

  for (const foto of fotos) {
    const url = (foto && foto.url_original) || "";
    if (!url || urlsProcessadas.has(url)) continue;
    urlsProcessadas.add(url);

    rows.push({
      json: {
        id: idEstabelecimento,
        foto_index: foto.foto_index ?? null,
        url: url
      }
    });
  }
}

return rows;

// Mode: Run Once for All Items
const items = $input.all();
return items.map((item) => {
  const e = item.json || {};

  let fotos = [];
  try {
    fotos = typeof e.fotos === "string" ? JSON.parse(e.fotos) : (e.fotos || []);
  } catch (err) {
    fotos = [];
  }
  if (!Array.isArray(fotos)) fotos = [];

  const fotosOrdenadas = [...fotos].sort((a, b) => {
    const na = (a && typeof a.nota_capa === "number") ? a.nota_capa : -Infinity;
    const nb = (b && typeof b.nota_capa === "number") ? b.nota_capa : -Infinity;

    // Primeiro: nota decrescente
    if (nb !== na) return nb - na;

    // Desempate: foto_index crescente (menor index primeiro)
    const ia = (a && typeof a.foto_index === "number") ? a.foto_index : Infinity;
    const ib = (b && typeof b.foto_index === "number") ? b.foto_index : Infinity;
    return ia - ib;
  });

  return {
    json: {
      ...e,
      fotos: fotosOrdenadas,
    },
  };
});

// Mode: Run Once for All Items
const SUPABASE_URL = "https://veedrfffsquvyypjrquh.supabase.co";
const BUCKET = "TRIP";
const KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InZlZWRyZmZmc3F1dnl5cGpycXVoIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODg2OTQyMSwiZXhwIjoyMDk0NDQ1NDIxfQ.0Z341oGGbmFl2ce8TLVTs55F2667wdug0aF1iFNSNVw";
const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 1500;
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const extPorContentType = (ct) => {
  if (!ct) return "jpg";
  if (ct.includes("png")) return "png";
  if (ct.includes("webp")) return "webp";
  if (ct.includes("gif")) return "gif";
  return "jpg";
};

// Lista arquivos já existentes numa "pasta" (prefixo) do bucket
const listarFotosExistentes = async (id) => {
  try {
    const resp = await this.helpers.httpRequest({
      method: "POST",
      url: `${SUPABASE_URL}/storage/v1/object/list/${BUCKET}`,
      timeout: 20000,
      json: true,
      headers: {
        Authorization: `Bearer ${KEY}`,
        "Content-Type": "application/json",
      },
      body: {
        prefix: `${id}/`,
        limit: 1000,
        offset: 0,
        sortBy: { column: "name", order: "asc" },
      },
    });
    return (resp || [])
      .filter((f) => f.id !== null) // ignora "subpastas"
      .map((f) => {
        const path = `${id}/${f.name}`;
        return {
          name: f.name,
          path,
          public_url: `${SUPABASE_URL}/storage/v1/object/public/${BUCKET}/${path}`,
        };
      });
  } catch (err) {
    return [];
  }
};

const items = $input.all();
const contadorPorId = {};
const resultados = [];

// Cache para não listar o mesmo id várias vezes
const galleryCache = {};
const galleryReportado = {};

for (const item of items) {
  const e = item.json || {};
  let url = e.url || e.url_original;
  const id = e.id || "sem_id";
  if (!url) continue;

  // Lista uma vez por id e emite um item de "gallery" com as fotos existentes
  if (!(id in galleryCache)) {
    galleryCache[id] = await listarFotosExistentes(id);
  }
  if (!galleryReportado[id]) {
    galleryReportado[id] = true;
    resultados.push({
      json: {
        id,
        tipo: "gallery_existente",
        total: galleryCache[id].length,
        fotos: galleryCache[id],
      },
    });
  }

  if (url.includes("googleusercontent.com")) {
    url = url.replace(/=w\d+-h\d+.*$/i, "=w1600-h1600-k-no");
  }

  const idx = contadorPorId[id] ?? 0;
  contadorPorId[id] = idx + 1;

  let img = null;
  let lastErr = null;
  for (let tentativa = 1; tentativa <= MAX_RETRIES; tentativa++) {
    try {
      img = await this.helpers.httpRequest({
        method: "GET",
        url,
        encoding: "arraybuffer",
        returnFullResponse: true,
        timeout: 20000,
        headers: {
          "User-Agent":
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          Accept: "image/webp,image/apng,image/*,*/*;q=0.8",
        },
      });
      break;
    } catch (err) {
      lastErr = err;
      const status = err.response?.statusCode || err.statusCode;
      if (status === 403 || status === 404) break;
      if (tentativa < MAX_RETRIES) await sleep(RETRY_DELAY_MS * tentativa);
    }
  }

  if (!img || !img.body || img.body.length === 0) {
    const status =
      lastErr?.response?.statusCode || lastErr?.statusCode || "vazio";
    resultados.push({
      json: {
        id,
        foto_index: idx,
        url,
        sucesso: false,
        erro: `download_falhou_${status}`,
      },
    });
    continue;
  }

  const contentType = img.headers["content-type"] || "image/jpeg";
  const ext = extPorContentType(contentType);
  const path = `${id}/${idx}.${ext}`;

  let uploadOk = false;
  let uploadErr = null;
  for (let tentativa = 1; tentativa <= MAX_RETRIES; tentativa++) {
    try {
      await this.helpers.httpRequest({
        method: "POST",
        url: `${SUPABASE_URL}/storage/v1/object/${BUCKET}/${path}`,
        timeout: 30000,
        headers: {
          Authorization: `Bearer ${KEY}`,
          "Content-Type": contentType,
          "x-upsert": "true",
        },
        body: Buffer.from(img.body),
      });
      uploadOk = true;
      break;
    } catch (err) {
      uploadErr = err;
      if (tentativa < MAX_RETRIES) await sleep(RETRY_DELAY_MS * tentativa);
    }
  }

  if (!uploadOk) {
    resultados.push({
      json: {
        id,
        foto_index: idx,
        url,
        path,
        sucesso: false,
        erro:
          "upload_falhou: " +
          JSON.stringify(
            uploadErr?.response?.body ??
              uploadErr?.response?.data ??
              uploadErr?.message
          ),
      },
    });
    continue;
  }

  resultados.push({
    json: {
      id,
      foto_index: idx,
      path,
      sucesso: true,
      public_url: `${SUPABASE_URL}/storage/v1/object/public/${BUCKET}/${path}`,
    },
  });
}

return resultados;

// Mode: Run Once for All Items
// Agrupa imagens por estabelecimento (id). Novas primeiro, existentes depois.
const items = $input.all();
const porId = {};

const garantirGrupo = (id) => {
  if (!porId[id]) {
    porId[id] = { id, _temp: [], _existentes: [] };
  }
  return porId[id];
};

for (const item of items) {
  const e = item.json || {};
  const id = e.id;
  if (!id) continue;

  const grupo = garantirGrupo(id);

  // Item de galeria existente: extrai as URLs já salvas
  if (e.tipo === "gallery_existente") {
    if (Array.isArray(e.fotos)) {
      for (const f of e.fotos) {
        const u = typeof f === "string" ? f : f?.public_url;
        if (u) grupo._existentes.push(u);
      }
    }
    continue;
  }

  // Item normal de upload
  if (e.public_url && e.sucesso !== false) {
    grupo._temp.push({
      foto_index: typeof e.foto_index === "number" ? e.foto_index : 9999,
      url: e.public_url,
    });
  }
}

return Object.values(porId).map((grupo) => {
  // ordena os uploads novos por foto_index (0, 1, 2, ...)
  grupo._temp.sort((a, b) => a.foto_index - b.foto_index);
  const novas = grupo._temp.map((f) => f.url);

  // novas primeiro, existentes depois — sem duplicatas
  const fotos = [...new Set([...novas, ...grupo._existentes])];

  return {
    json: {
      id: grupo.id,
      qtd_fotos: fotos.length,
      capa: novas[0] ?? grupo._existentes[0] ?? null, // capa = primeira recém-enviada
      fotos,
    },
  };
});

const items = $input.all().map(i => i.json);

const uploads = {};
const estabelecimentos = {};

for (const item of items) {
  const id = item.id;
  if (!id) continue;
  if (item.capa && !item.nome) {
    uploads[id] = item;
  } else if (item.nome) {
    estabelecimentos[id] = item;
  }
}

const todosIds = new Set([
  ...Object.keys(estabelecimentos),
  ...Object.keys(uploads),
]);

return [...todosIds].map(id => {
  const est = estabelecimentos[id] || {};
  const upload = uploads[id];

  const capa = upload
    ? (upload.capa ?? null)
    : (est.capa ?? null);

  const fotos_salvas = upload
    ? (upload.fotos ?? [])
    : (est.fotos_salvas ?? []);

  const qtd_fotos_salvas = upload
    ? (upload.qtd_fotos ?? (Array.isArray(upload.fotos) ? upload.fotos.length : 0))
    : (est.qtd_fotos_salvas ?? 0);

  return {
    json: {
      ...est,            // todos os campos do estabelecimento (nome, reviews, etc.)
      id,
      capa,
      fotos_salvas,
      qtd_fotos_salvas,
    },
  };
});

// Run Once for All Items
const items = $input.all().map(i => i.json ?? {});

// desencapsula string JSON aninhada (resolve double/triple-encoding)
function unwrapDeep(v) {
  let cur = v;
  for (let i = 0; i < 5; i++) {
    if (typeof cur !== 'string') break;
    const s = cur.trim();
    if (s === '') return null;
    try { cur = JSON.parse(s); } catch { return cur; }
  }
  return cur;
}

// converte para objeto/array sem quebrar o node se vier malformado
function toJsonbSafe(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'string') { try { return JSON.parse(v); } catch { return v; } }
  return v;
}

return items.map(item => {
  return {
    json: {
      id: item.id ?? null,
      nome: item.nome ?? null,
      subtipos: item.subtipos ?? null,
      endereco: item.endereco ?? null,
      bairro: item.bairro ?? null,
      cep: item.cep ?? null,
      cidade: item.cidade ?? null,
      estado: item.estado ?? null,
      pais: item.pais ?? null,
      telefone: item.telefone ?? null,
      telefone_extra: item.telefone_extra ?? null,
      email: item.email ?? null,
      website: item.website ?? null,
      instagram: item.instagram ?? null,
      facebook: item.facebook ?? null,
      link_google_maps: item.link_google_maps ?? null,
      nota: item.nota ?? null,
      qtd_avaliacoes: item.qtd_avaliacoes ?? null,
      distribuicao_notas: unwrapDeep(item.distribuicao_notas),  // desencapa aspas extras
      status: item.status ?? null,
      horarios: unwrapDeep(item.horarios),                       // desencapa aspas extras
      faixa_preco: item.faixa_preco ?? null,
      qtd_fotos: item.qtd_fotos_salvas ?? item.qtd_fotos ?? null,
      gallery: item.fotos_salvas ?? item.gallery ?? [],
      capa: item.capa ?? null,
      fotos: item.fotos ?? null,
      resumo: item.resumo ?? null,
      details_google: item.details_google ?? null,
      google_id: item.google_id ?? null,
      place_id: item.place_id ?? null,
      verificado: item.verificado ?? null,
      timezone: item.timezone ?? null,
      reviews: toJsonbSafe(item.reviews),                        // blindado contra malformado
      par1: item.par1 ?? null,
      just1: item.just1 ?? null,
      par2: item.par2 ?? null,
      just2: item.just2 ?? null,
      par3: item.par3 ?? null,
      just3: item.just3 ?? null,
      par4: item.par4 ?? null,
      just4: item.just4 ?? null,
      par5: item.par5 ?? null,
      just5: item.just5 ?? null,
      "média": item["média"] ?? null,
      aproved: item.aproved ?? null,
      reason: item.reason ?? null,
      segmento: item.segmento ?? null,
      subsegmento: item.subsegmento ?? null,
      acessibilidade: item.acessibilidade ?? null,
      nr_latitude: item.nr_latitude ?? null,
      nr_longitude: item.nr_longitude ?? null,
      minimum_grade: item.minimum_grade ?? null,
      Reevaluation: item.Reevaluation ?? null,
      go_to_reevaluation: true,
    }
  };
});

// Mode: Run Once for All Items
// Gera UMA row por foto (para o Switch funcionar), sem duplicatas e COM O ID do restaurante.
const categoriasInuteis = ["Street View & 360°", "Videos", "Menu"];
const rows = [];
// 1. Pega TODOS os restaurantes que entraram no nó
const items = $input.all();
for (const item of items) {
  const e = item.json || {};
  const idEstabelecimento = e.id || null;
  const fotos = Array.isArray(e.fotos) ? e.fotos : [];
  const urlsProcessadas = new Set();
  // 2. Transforma cada foto em um item isolado
  for (let i = 0; i < fotos.length; i++) {
    const foto = fotos[i] || {};
    // O input novo usa "url_original"; mantém fallback para "url"
    const url = foto.url_original || foto.url || "";
    const description = foto.description || "";
    if (!url || urlsProcessadas.has(url)) {
      continue;
    }
    // eh_inutil já vem calculado; só recalcula se não vier
    const ehInutil =
      typeof foto.eh_inutil === "boolean"
        ? foto.eh_inutil
        : categoriasInuteis.includes(description) || url.includes("streetviewpixels");
    urlsProcessadas.add(url);
    // 3. Joga a foto na lista final
    rows.push({
      json: {
        id: idEstabelecimento,                       // ID do restaurante blindado
        foto_index: foto.foto_index ?? i,            // usa o do input; senão o índice do loop
        description: description,
        url_original: url,
        eh_inutil: ehInutil,
        nota_capa: foto.nota_capa ?? null,
        justificativa_capa: foto.justificativa_capa ?? null,
        serve_como_capa: foto.serve_como_capa ?? false
      }
    });
  }
}
// Retorna uma lista plana (1 item = 1 foto)
return rows;

// Mode: Run Once for All Items
const items = $input.all().map(i => i.json).flat();

const parseReview = (texto) => {
  if (!texto || typeof texto !== 'string') {
    return { nota: null, justificativa: null };
  }
  if (texto.trim() === '77') {
    return { nota: 'insuficiente', justificativa: null };
  }
  const idx = texto.indexOf(':');

  // SEM dois-pontos: pode ser nota seca tipo "8.0" -> trata como nota
  if (idx === -1) {
    const soNota = texto.trim().replace(',', '.');
    if (/^\d{1,2}(\.\d+)?$/.test(soNota)) {
      const n = parseFloat(soNota);
      return { nota: isNaN(n) ? null : n, justificativa: null };
    }
    return { nota: null, justificativa: texto.trim() };
  }

  // COM dois-pontos
  const notaRaw = texto.slice(0, idx).trim().replace(',', '.');

  // "77: justificativa" -> insuficiente, preservando a justificativa
  if (notaRaw === '77') {
    return { nota: 'insuficiente', justificativa: texto.slice(idx + 1).trim() };
  }

  const nota = parseFloat(notaRaw);
  return {
    nota: isNaN(nota) ? null : nota,
    justificativa: texto.slice(idx + 1).trim(),
  };
};

const estabelecimentos = items.filter(i => i && i.nome !== undefined);
const reviewItems = items.filter(i => {
  if (!i || i.nome !== undefined) return false;
  const k = Object.keys(i)[0];
  return k && k.endsWith('_review');
});

const reviewsPorId = /** @type {Record<string, any>} */ ({});
for (const item of reviewItems) {
  const [chave, valorBruto] = Object.entries(item)[0];
  const nomeAtributo = chave.replace(/_review$/, '');
  try {
    const dadosIA = JSON.parse(valorBruto);
    const idEstabelecimento = dadosIA.id;
    const resultadoIA = String(dadosIA.resultado || '');
    if (!idEstabelecimento) continue;
    if (!reviewsPorId[idEstabelecimento]) {
      reviewsPorId[idEstabelecimento] = { notasNum: [] };
    }
    const { nota, justificativa } = parseReview(resultadoIA);
    const alvo = reviewsPorId[idEstabelecimento];
    const chaveNota = `${nomeAtributo}_nota`;
    const chaveJust = `${nomeAtributo}_justificativa`;
    const jaTemNota = typeof alvo[chaveNota] === 'number' || alvo[chaveNota] === 'insuficiente';
    const novaTemNota = typeof nota === 'number' || nota === 'insuficiente';
    // Só grava se a chave ainda não existe OU se o novo registro traz nota.
    // Nunca deixa um item SEM nota apagar um que já tinha nota válida.
    if (!(chaveNota in alvo) || novaTemNota) {
      if (!(jaTemNota && !novaTemNota)) {
        alvo[chaveNota] = nota;
        alvo[chaveJust] = justificativa;
        if (typeof nota === 'number') {
          if (!alvo.notasNum.includes(nota)) alvo.notasNum.push(nota);
        }
      }
    }
  } catch (error) {
    continue;
  }
}

const summaryPorId = /** @type {Record<string, string>} */ ({});
for (const item of items) {
  if (!item || !item.summary) continue;
  try {
    const dados = JSON.parse(item.summary);
    if (dados.id && dados.resultado) {
      summaryPorId[dados.id] = dados.resultado;
    }
  } catch (error) {
    continue;
  }
}

return estabelecimentos.map(est => {
  const idAtual = est.id;
  const dadosDoEstabelecimento = reviewsPorId[idAtual] || { notasNum: [] };
  const arrayDeNotas = dadosDoEstabelecimento.notasNum;
  const media = arrayDeNotas.length
    ? Math.round((arrayDeNotas.reduce((a, b) => a + b, 0) / arrayDeNotas.length) * 100) / 100
    : null;
  delete dadosDoEstabelecimento.notasNum;
  return {
    json: {
      ...est,
      ...dadosDoEstabelecimento,
      resumo: summaryPorId[idAtual] || est.resumo || null,
      media_reviews: media,
    }
  };
});

const items = $input.all().map(i => i.json);

const fotosPorId = /** @type {Record<string, any[]>} */ ({});

for (const item of items) {
  if (item && item.id && item.foto_index !== undefined && !item.eh_inutil && item.nota_capa >= 6) {
    if (!fotosPorId[item.id]) {
      fotosPorId[item.id] = [];
    }
    fotosPorId[item.id].push(item);
  }
}

const resultados = Object.keys(fotosPorId).map(id => {
  const fotosDoEstabelecimento = fotosPorId[id];

  fotosDoEstabelecimento.sort((a, b) => a.foto_index - b.foto_index);

  return {
    json: {
      id: id,
      fotos_analise: fotosDoEstabelecimento
    }
  };
});

return resultados;

// Run Once for All Items

const all = $input.all().map(item => item.json);

const agrupados = {};

for (const item of all) {
  const id = item.id;

  if (!id) continue;

  if (!agrupados[id]) {
    agrupados[id] = {
      id
    };
  }

  for (const [key, value] of Object.entries(item)) {

    // ignora campos vazios
    if (
      value === undefined ||
      value === null ||
      value === ''
    ) {
      continue;
    }

    // mantém arrays completos
    if (Array.isArray(value)) {
      agrupados[id][key] = value;
      continue;
    }

    // mantém objetos completos
    if (typeof value === 'object') {
      agrupados[id][key] = value;
      continue;
    }

    // mantém valores simples
    agrupados[id][key] = value;
  }
}

return Object.values(agrupados).map(item => ({
  json: item
}));

