// Mode: Run Once for Each Item — GERAL (qualquer segmento)
//
// CORREÇÃO PRINCIPAL:
// As notas chegam como STRING "insuficiente" (não como o número 77).
// O código antigo só reconhecia === 77, então "insuficiente" escapava
// da média E do tally de não-avaliadas. Agora tudo passa por normalizar():
//   - "insuficiente" / "77" / 77   -> SENTINELA (77) = sem dados
//   - número (ou "7,5" / "7.5")     -> número
//   - null / undefined / ""         -> null = não se aplica ao segmento (não conta)
//
// MÍNIMOS:
//   - food e fun  => MIN_FOOD_FUN (6 fixo)
//   - média       => MIN (vem de minimum_grade; fallback 6)
// FOOD é portão crítico: insuficiente OU nota < MIN_FOOD_FUN => reprova.
//   - PORÉM: se já reprovou por >2 insuficientes, a justificativa fica só a dos insuficientes.

const e = $input.item.json;

const SENTINELA = 77;
const MAX_NAO_AVALIADAS = 2; // acima disso (>2 => 3+) reprova
const MIN_FOOD_FUN = 6;      // mínimo fixo para comida e diversão

const ehNotaValida = (v) =>
  typeof v === "number" && Number.isFinite(v) && v !== SENTINELA;

const MIN = ehNotaValida(e.minimum_grade) ? e.minimum_grade : 6; // mínimo da média

const round = (x, d = 2) => {
  if (x === null || x === undefined || Number.isNaN(x) || !Number.isFinite(x)) {
    return null;
  }
  const f = Math.pow(10, d);
  return Math.round(x * f) / f;
};

// --------------------
// NORMALIZAÇÃO (a peça que faltava)
// --------------------
const normalizar = (v) => {
  if (v === null || v === undefined) return null;          // ausente
  if (typeof v === "number") return Number.isFinite(v) ? v : null;
  if (typeof v === "string") {
    const s = v.trim().toLowerCase();
    if (s === "") return null;                             // vazio => ausente
    if (s === "insuficiente") return SENTINELA;            // insuficiente
    const n = Number(s.replace(",", "."));
    if (Number.isFinite(n)) return n;                      // "77"->77, "7,5"->7.5
    return SENTINELA;                                      // texto inesperado => insuficiente
  }
  return null;
};

// Todas as notas possíveis, JÁ normalizadas
const candidatas = {
  variety: normalizar(e.variety_nota),
  service: normalizar(e.service_nota),
  price_to_value: normalizar(e.price_to_value_nota),
  capacity: normalizar(e.capacity_nota),
  beauty: normalizar(e.beauty_nota),
  space: normalizar(e.space_nota),
  fun: normalizar(e.fun_nota),
  food: normalizar(e.food_nota),
};

const rotulos = {
  variety: "variedade",
  service: "atendimento",
  price_to_value: "custo-benefício",
  capacity: "capacidade",
  beauty: "beleza",
  space: "espaço",
  fun: "diversão",
  food: "comida",
};

// --------------------
// MÉDIA
// --------------------
const presentes = Object.entries(candidatas).filter(([, v]) => ehNotaValida(v));
const notasUsadas = presentes.map(([, v]) => v);
const media = notasUsadas.length
  ? notasUsadas.reduce((a, b) => a + b, 0) / notasUsadas.length
  : null;

// --------------------
// NÃO AVALIADAS (insuficientes) — agora pega "insuficiente"/77 igual
// --------------------
const notasNaoAvaliadas = Object.entries(candidatas)
  .filter(([, v]) => v === SENTINELA)
  .map(([k]) => k);

const reprovaPorInsuficientes = notasNaoAvaliadas.length > MAX_NAO_AVALIADAS;

// --------------------
// REGRAS
// --------------------
const motivos = [];
const observacoes = [];

// FOTOS (crítico)
const temFotoAnalise = Array.isArray(e.fotos_analise) && e.fotos_analise.length > 0;
if (!temFotoAnalise) {
  motivos.push("Sem fotos analisadas (fotos_analise ausente ou vazio)");
}

// FOOD (crítico) — insuficiente REPROVA; mínimo = MIN_FOOD_FUN
// Se já reprovou por >2 insuficientes, NÃO duplica o motivo de comida insuficiente.
const foodN = candidatas.food;
if (foodN !== null) {
  if (foodN === SENTINELA) {
    if (!reprovaPorInsuficientes) {
      motivos.push("Comida não pôde ser avaliada (insuficiente)");
    }
  } else if (foodN < MIN_FOOD_FUN) {
    motivos.push(`Nota de comida abaixo de ${MIN_FOOD_FUN} (food_nota=${round(foodN)})`);
  }
}

// FUN (crítico) — mínimo = MIN_FOOD_FUN
const funN = candidatas.fun;
if (funN !== null) {
  if (funN === SENTINELA) {
    if (!reprovaPorInsuficientes) {
      observacoes.push("diversão não pôde ser avaliada (insuficiente)");
    }
  } else if (funN < MIN_FOOD_FUN) {
    motivos.push(`Nota de diversão abaixo de ${MIN_FOOD_FUN} (fun_nota=${round(funN)})`);
  }
}

// NÃO AVALIADAS (crítico) — mais de 2 insuficientes => reprova
if (reprovaPorInsuficientes) {
  const nomes = notasNaoAvaliadas.map((k) => rotulos[k] || k);
  motivos.push(
    `Notas insuficientes: ${notasNaoAvaliadas.length} notas sem dados ` +
    `— máximo permitido é ${MAX_NAO_AVALIADAS} (${nomes.join(", ")})`
  );
}

// MÉDIA — não repete "sem notas válidas" se já reprovou por excesso de insuficientes
if (media === null) {
  if (!reprovaPorInsuficientes) {
    motivos.push("Sem notas qualitativas válidas para calcular a média");
  }
} else if (media < MIN) {
  motivos.push(`media das notas qualitativas abaixo do corte (${MIN})`);
}

const aprovado = motivos.length === 0;

// --------------------
// JUSTIFICATIVA
// --------------------
let motivo;

if (aprovado) {
  const partes = [`Média das notas qualitativas ${round(media)} (≥ ${MIN})`];
  if (ehNotaValida(foodN)) partes.push(`comida ${round(foodN)} (≥ ${MIN_FOOD_FUN})`);
  if (ehNotaValida(funN)) partes.push(`diversão ${round(funN)} (≥ ${MIN_FOOD_FUN})`);
  if (observacoes.length) partes.push(...observacoes);
  if (notasNaoAvaliadas.length) {
    const nomes = notasNaoAvaliadas.map((k) => rotulos[k] || k);
    partes.push(`não avaliadas: ${nomes.join(", ")}`);
  }
  motivo = "Aprovado — " + partes.join("; ");
} else {
  let txt = "Reprovado — " + motivos.join(" | ");
  if (observacoes.length) txt += " | (obs: " + observacoes.join("; ") + ")";
  motivo = txt;
}

// --------------------
// OUTPUT
// --------------------
return {
  json: {
    ...e,
    minimum_grade_usado: MIN,
    min_food_fun_usado: MIN_FOOD_FUN,
    media_qualitativa: round(media),
    notas_consideradas: notasUsadas.length,
    notas_usadas: presentes.map(([k]) => k),
    notas_nao_avaliadas: notasNaoAvaliadas,
    qtd_notas_nao_avaliadas: notasNaoAvaliadas.length,
    tem_fotos_analise: temFotoAnalise,
    aprovado_notas: aprovado,
    motivo_notas: motivo,
  }
};

const items = $input.all();

// timestamp atual no horário do Brasil (America/Sao_Paulo), ISO com offset
function tsBrasil() {
  return new Date()
    .toLocaleString('sv-SE', { timeZone: 'America/Sao_Paulo' })
    .replace(' ', 'T') + '-03:00';
}

for (const item of items) {
  const dados = item.json || {};

  // --- 1. Filtro + ordenação de fotos ---
  if (Array.isArray(dados.fotos_analise)) {
    dados.fotos_analise = dados.fotos_analise
      .filter((foto) => {
        const nota = Number(foto?.nota_capa ?? 0);
        const inutil = foto?.eh_inutil === true;
        return !inutil && nota >= 6;
      })
      .sort((a, b) => Number(b?.nota_capa ?? 0) - Number(a?.nota_capa ?? 0));
  }

  // --- 2. Reevaluation (objeto): mantém a média antiga, resto sobrescreve ---
  let prev = dados.Reevaluation;
  if (typeof prev === 'string' && prev.trim()) {
    try { prev = JSON.parse(prev); } catch (e) { prev = null; }
  }
  if (Array.isArray(prev) || typeof prev !== 'object') prev = null;

  // média: mantém a antiga como veio; ignora a nova
  const mediaAntiga = (prev && prev['média'] != null) ? prev['média'] : null;

  // sessao = anterior + 1 (1 na primeira vez)
  const sessaoPrev = (prev && Number.isFinite(Number(prev.sessao))) ? Number(prev.sessao) : 0;

  const agora = tsBrasil();
  dados.Reevaluation = {
    'média': mediaAntiga,                       // mantém a antiga, ignora a nova
    aproved: dados.aprovado_notas === true,     // novo (sobrescreve)
    reason: dados.motivo_notas ?? null,         // novo
    data: agora,                                // novo
    sessao: sessaoPrev + 1,                     // anterior + 1
    updated_at: agora,                          // sobrescreve com agora
  };

  item.json = dados;
}

return items;

// Mode: Run Once for All Items
const items = $input.all().map(i => i.json);

// Uma FOTO tem url_original. Uma RESPOSTA da IA tem o JSON com "resultado".
// Um mesmo item nunca é os dois ao mesmo tempo, então separamos com prioridade
// para a resposta: se parece resposta, é resposta; senão, se tem url, é foto.
function looksLikeResposta(i) {
  if (!i) return false;
  if (i.choices !== undefined) return true;
  if (i.message?.content !== undefined) return true;
  if (typeof i.content === 'string') return true;
  if (typeof i.resultado === 'string') return true;
  return false;
}

const respostasRaw = items.filter(i => looksLikeResposta(i));
const fotos = items.filter(i => !looksLikeResposta(i) && i.url_original !== undefined);

function parseResposta(aiOutput) {
  if (!aiOutput) return null;

  // 1) Extrai o texto bruto de onde quer que ele esteja
  let rawText = "";
  if (aiOutput.choices && aiOutput.choices[0] && aiOutput.choices[0].message) {
    rawText = aiOutput.choices[0].message.content;
  } else if (typeof aiOutput.content === 'string') {
    rawText = aiOutput.content;
  } else if (typeof aiOutput === 'string') {
    rawText = aiOutput;
  } else if (typeof aiOutput.resultado === 'string') {
    // caso o item já venha "achatado" com resultado/id/foto_index no topo
    rawText = JSON.stringify(aiOutput);
  }
  if (!rawText) return null;

  // 2) Tenta parsear o JSON da IA
  let parsedJson = null;
  try {
    let fixedText = rawText.trim();
    // tira cercas de markdown se a IA escapou e mandou ```json ... ```
    fixedText = fixedText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    if (!fixedText.endsWith('}')) fixedText += '\n}';
    parsedJson = JSON.parse(fixedText);
  } catch (e) {
    parsedJson = null;
  }

  // 3) Se parseou, extrai pelos campos; senão cai no regex
  let id = null;
  let foto_index = null;
  let resultado = "";

  if (parsedJson) {
    id = parsedJson.id ?? null;
    foto_index = parsedJson.foto_index ?? null;
    resultado = parsedJson.resultado || "";
  } else {
    const idMatch = rawText.match(/"id"\s*:\s*"([^"]+)"/);
    const fiMatch = rawText.match(/"foto_index"\s*:\s*(\d+)/);
    const resMatch = rawText.match(/"resultado"\s*:\s*"([^"]*(?:\\.[^"]*)*)"/);
    id = idMatch ? idMatch[1] : null;
    foto_index = fiMatch ? parseInt(fiMatch[1], 10) : null;
    resultado = resMatch ? resMatch[1].replace(/\\"/g, '"') : "";
  }

  // normaliza foto_index para número inteiro quando possível
  if (foto_index !== null && foto_index !== undefined) {
    const fiNum = parseInt(foto_index, 10);
    foto_index = isNaN(fiNum) ? null : fiNum;
  }

  // 4) Separa nota e justificativa de "N.N: justificativa"
  let nota = null;
  let justificativa = null;
  if (resultado && resultado.trim() !== "") {
    const idx = resultado.indexOf(":");
    if (idx !== -1) {
      const notaNum = parseFloat(resultado.slice(0, idx).trim().replace(",", "."));
      nota = isNaN(notaNum) ? null : notaNum;
      justificativa = resultado.slice(idx + 1).trim();
    } else {
      justificativa = resultado.trim();
    }
  }

  return {
    id,
    foto_index,
    nota,
    justificativa,
    resposta_bruta: rawText,
  };
}

// Indexa as respostas por chave "id__foto_index".
// Se houver vários ids diferentes e/ou vários foto_index, cada par é único.
const respMap = new Map();
for (const r of respostasRaw) {
  const p = parseResposta(r);
  if (!p || p.id === null || p.foto_index === null) continue;
  const key = `${p.id}__${p.foto_index}`;
  // não sobrescreve uma resposta já casada (mantém a primeira válida)
  if (!respMap.has(key)) respMap.set(key, p);
}

// Casa cada foto com sua resposta pela chave id+foto_index (não por posição)
const rows = fotos.map((foto) => {
  const key = `${foto.id}__${foto.foto_index}`;
  const parsed = respMap.get(key) || { nota: null, justificativa: null, resposta_bruta: null };
  return {
    id: foto.id,
    foto_index_original: foto.foto_index, // guarda o original pra desempate
    description: foto.description,
    url_original: foto.url_original,
    eh_inutil: foto.eh_inutil,
    nota_capa: parsed.nota,
    justificativa_capa: parsed.justificativa,
    resposta_bruta: parsed.resposta_bruta,
    serve_como_capa: parsed.nota !== null && parsed.nota >= 7,
  };
});

// Agrupa por id: o ranking/reindex de foto_index é feito DENTRO de cada id,
// para funcionar quando o batch traz vários estabelecimentos misturados.
const porId = new Map();
for (const row of rows) {
  if (!porId.has(row.id)) porId.set(row.id, []);
  porId.get(row.id).push(row);
}

const out = [];
for (const grupo of porId.values()) {
  // Ordena por nota decrescente; empate: foto_index_original crescente
  grupo.sort((a, b) => {
    const na = a.nota_capa ?? -Infinity;
    const nb = b.nota_capa ?? -Infinity;
    if (nb !== na) return nb - na;
    return (a.foto_index_original ?? Infinity) - (b.foto_index_original ?? Infinity);
  });

  // Reatribui foto_index em ordem crescente conforme a posição pós-sort,
  // por estabelecimento (0 = melhor foto daquele id)
  grupo.forEach((row, i) => {
    out.push({
      json: {
        id: row.id,
        foto_index: i, // 0 = melhor foto deste id, 1 = segunda melhor, etc.
        description: row.description,
        url_original: row.url_original,
        eh_inutil: row.eh_inutil,
        nota_capa: row.nota_capa,
        justificativa_capa: row.justificativa_capa,
        resposta_bruta: row.resposta_bruta,
        serve_como_capa: row.serve_como_capa,
      }
    });
  });
}

return out;

// Mode: Run Once for All Items
// Adiciona campos de avaliação de capa em cada foto.
// Fotos marcadas como eh_inutil recebem valores padrão de rejeição automática.

const items = $input.all().map(i => i.json);

const rows = items.map(foto => {
  if (foto.eh_inutil) {
    return {
      json: {
        ...foto,
        nota_capa: 0,
        justificativa_capa: "Imagem do Google Street View (ou outras), inadequada como capa de perfil profissional.",
        resposta_bruta: "Imagem do Google Street View (ou outras), inadequada como capa de perfil profissional.",
        serve_como_capa: false,
      }
    };
  }

  // Foto útil: campos vazios, prontos para serem preenchidos pela IA depois
  return {
    json: {
      ...foto,
      nota_capa: null,
      justificativa_capa: null,
      resposta_bruta: null,
      serve_como_capa: null,
    }
  };
});

return rows;

const inputItems = $input.all();
const previousItems = $('Switch1').all();

const vistos = new Set();

return inputItems.map((item, index) => {
  const original = previousItems[index].json;

  // Erro de download/processamento → inútil
  if (item.json.error) {
    return {
      json: {
        ...original,        // url_original preservada
        eh_inutil: true
      }
    };
  }

  // Chave SÓ para comparação (não afeta o que sai no fluxo)
  const chaveComparacao = (original.url_original || '')
    .split('?')[0]
    .replace(/=s\d+-k-no$/, '')
    .replace(/=s\d+.*$/, '');

  const ehDuplicata = Boolean(chaveComparacao) && vistos.has(chaveComparacao);
  if (chaveComparacao && !ehDuplicata) {
    vistos.add(chaveComparacao);
  }

  return {
    json: {
      ...original,          // url_original sai exatamente como entrou
      eh_inutil: original.eh_inutil || ehDuplicata
    }
  };
});

// Limpa a saída dos agentes mas MANTÉM cada campo de review como STRING JSON,
// e MANTÉM os itens separados (é o que o Organizer espera receber).
// Só desembrulha {action,text} e normaliza, sem mudar a estrutura.
// Detecta automaticamente qualquer campo "*_review" + "summary", então
// funciona em qualquer fluxo (service, food, fun, beauty, etc.).

function ehCampoReview(chave) {
  return chave === "summary" || chave.endsWith("_review");
}

function limpaParaString(valor) {
  if (valor == null) return valor;
  let obj = (typeof valor === "object") ? valor : null;
  if (obj === null && typeof valor === "string") {
    try { obj = JSON.parse(valor.trim()); } catch (e) { return valor; } // não parseou: devolve como veio
  }
  if (!obj) return valor;
  // desembrulha {action:"parse", text:"{...}"}
  if (obj.text && (obj.action || obj.resultado === undefined)) {
    try {
      const inner = JSON.parse(obj.text);
      if (inner && (inner.resultado !== undefined || inner.id !== undefined)) obj = inner;
    } catch (e) {}
  }
  // re-serializa como string JSON limpa { id, resultado }
  return JSON.stringify({
    id: obj.id ?? null,
    resultado: obj.resultado ?? null
  });
}

const out = [];
for (const item of $input.all()) {
  const novo = { ...item.json };
  for (const campo of Object.keys(novo)) {
    if (ehCampoReview(campo) && novo[campo] !== undefined) {
      novo[campo] = limpaParaString(novo[campo]);
    }
  }
  out.push({ json: novo });
}
return out;

// Lê o campo existente SEM alterá-lo, e adiciona um campo novo com frases numeradas.
const texto = $json.comentarios_formatados || "";

// 1) separa cada "Comentário N: ..." preservando o número original
const blocos = texto
  .split(/\n\s*\n/)            // comentários são separados por linha em branco
  .map(b => b.trim())
  .filter(Boolean);

const linhas = [];
let contadorFrase = 0;

for (const bloco of blocos) {
  // remove o rótulo "Comentário N:" do início, guardando o número
  const m = bloco.match(/^Coment[áa]rio\s+(\d+)\s*:\s*([\s\S]*)$/i);
  const numComentario = m ? m[1] : "?";
  const corpo = m ? m[2] : bloco;

  // 2) quebra o corpo em frases (fim de frase ou quebra de linha)
  const frases = corpo
    .split(/(?<=[.!?])\s+|\n+/)
    .map(f => f.trim())
    .filter(f => f.length > 0);

  // se o comentário não tiver pontuação, ele inteiro vira uma "frase"
  const lista = frases.length ? frases : [corpo.trim()].filter(Boolean);

  for (const f of lista) {
    contadorFrase++;
    // formato: "F12 (C10): frase isolada"
    linhas.push(`F${contadorFrase} (C${numComentario}): ${f}`);
  }
}

// adiciona o campo novo, mantém todo o resto do item intacto
$json.comentarios_frases = linhas.join("\n");

return $input.item;

// Mode: Run Once for All Items
// Mantém todos os campos do estabelecimento e ADICIONA comentarios_formatados:
// todos os comentários juntos numa string, indicando cliente x resposta do dono.

const items = $input.all();

return items.map((item) => {
  const e = item.json || {};

  // "reviews" vem como STRING JSON — parseia
  let reviews = [];
  try {
    reviews = typeof e.reviews === "string" ? JSON.parse(e.reviews) : (e.reviews || []);
  } catch (err) {
    reviews = [];
  }
  if (!Array.isArray(reviews)) reviews = [];

  // Monta o bloco de comentários, separados e numerados,
  // com a resposta do dono identificada quando existir.
  const comentarios_formatados = reviews
    .filter((r) => r && r.review_text)
    .map((r, idx) => {
      const nota = r.review_rate ?? "?";
      const texto = String(r.review_text).replace(/\s+/g, " ").trim();

      let bloco = `Comentário ${idx + 1} (nota ${nota}) [CLIENTE]: ${texto}`;

      const resp = r.business_response_text;
      if (resp && String(resp).trim()) {
        const respLimpa = String(resp).replace(/\s+/g, " ").trim();
        bloco += `\n   ↳ [RESPOSTA DO DONO]: ${respLimpa}`;
      }

      return bloco;
    })
    .join("\n\n");

  return {
    json: {
      ...e,                      // mantém TODOS os campos originais do estabelecimento
      comentarios_formatados,    // adiciona o bloco de comentários
    },
  };
});
